#!/usr/bin/env node
// Embeds platform-specific FFmpeg binaries as gzipped base64 chunks in
// src/ffmpeg-bundle.js so packaged executables can extract them without
// relying on pkg asset globs.

'use strict';

const fs = require('fs');
const path = require('path');
const zlib = require('zlib');
const crypto = require('crypto');

const ROOT = path.resolve(__dirname, '..');
const VENDOR_DIR = path.join(ROOT, 'vendor', 'ffmpeg');
const OUTPUT = path.join(ROOT, 'src', 'ffmpeg-bundle.js');

const FFMPEG_BIN = process.platform === 'win32' ? 'ffmpeg.exe' : 'ffmpeg';
const FFPROBE_BIN = process.platform === 'win32' ? 'ffprobe.exe' : 'ffprobe';
const CHUNK_SIZE = 1024 * 1024;

const BINARIES = [
  ['ffmpeg', FFMPEG_BIN],
  ['ffprobe', FFPROBE_BIN],
];

function sha256(buffer) {
  return crypto.createHash('sha256').update(buffer).digest('hex');
}

function append(text) {
  fs.appendFileSync(OUTPUT, text, 'utf8');
}

function writeBinaryEntry(id, filename, trailingComma) {
  const filePath = path.join(VENDOR_DIR, filename);
  if (!fs.existsSync(filePath)) {
    console.error(`ERROR: missing ${filename}. Run node scripts/fetch-ffmpeg.js first.`);
    process.exit(1);
  }

  const data = fs.readFileSync(filePath);
  const gzipped = zlib.gzipSync(data, { level: zlib.constants.Z_BEST_COMPRESSION });
  const encoded = gzipped.toString('base64');
  const originalHash = sha256(data);
  const compressedHash = sha256(gzipped);

  append(`    ${JSON.stringify(id)}: {\n`);
  append(`      filename: ${JSON.stringify(filename)},\n`);
  append('      compression: \'gzip\',\n');
  append(`      size: ${data.length},\n`);
  append(`      sha256: ${JSON.stringify(originalHash)},\n`);
  append(`      compressedSize: ${gzipped.length},\n`);
  append(`      compressedSha256: ${JSON.stringify(compressedHash)},\n`);
  append('      data: [\n');

  for (let i = 0; i < encoded.length; i += CHUNK_SIZE) {
    const chunk = encoded.slice(i, i + CHUNK_SIZE);
    const suffix = i + CHUNK_SIZE < encoded.length ? ',' : '';
    append(`        ${JSON.stringify(chunk)}${suffix}\n`);
  }

  append(`      ]\n`);
  append(`    }${trailingComma ? ',' : ''}\n`);

  const sourceMb = (data.length / 1024 / 1024).toFixed(1);
  const packedMb = (gzipped.length / 1024 / 1024).toFixed(1);
  console.log(`Bundled ${filename}: ${sourceMb} MB -> ${packedMb} MB gzip`);
}

fs.mkdirSync(path.dirname(OUTPUT), { recursive: true });
fs.writeFileSync(
  OUTPUT,
  [
    '// AUTO-GENERATED by scripts/generate-ffmpeg-bundle.js. Do not edit by hand.',
    '// Platform-specific FFmpeg binaries, embedded as gzipped base64 chunks.',
    '// NOT committed to the repo (gitignored). Regenerated on each platform build.',
    '',
    '\'use strict\';',
    '',
    'module.exports = {',
    `  platform: ${JSON.stringify(process.platform)},`,
    `  arch: ${JSON.stringify(process.arch)},`,
    '  compression: \'gzip\',',
    '  binaries: {',
  ].join('\n') + '\n',
  'utf8',
);

for (let i = 0; i < BINARIES.length; i += 1) {
  const [id, filename] = BINARIES[i];
  writeBinaryEntry(id, filename, i < BINARIES.length - 1);
}

append('  }\n');
append('};\n');

console.log(`Generated ${OUTPUT} for ${process.platform}/${process.arch}.`);
